"Predictive Coding": {
  label: "Predictive Coding",
  summary: "Predictive coding is a theory from neuroscience and cognitive science that proposes the brain constantly makes predictions about incoming sensory information. Instead of processing all sensory data, the brain primarily focuses on \'prediction errors\'—the differences between what it expected and what it actually received—to update its internal models. In AI policy, understanding predictive coding helps us analyze how AI systems learn, make decisions, and handle unexpected situations, particularly in critical applications like autonomous vehicles or medical diagnostics. It also informs research into explainable AI, helping to understand how AI systems form their internal representations and react to novel data.",
  example: "A node tagged with this attribute might discuss how an autonomous vehicle\'s AI system updates its understanding of the road based on unexpected obstacles, or how to make such updates transparent.",
  frequency: "Appears in technical and ethical nodes discussing AI learning mechanisms, explainability, and reliability.",
  links: [
    { label: "Predictive coding", url: "https://en.wikipedia.org/wiki/Predictive_coding" }
  ]
},
"Predistribution economics (e.g., Jacob Hacker)": {
  label: "Predistribution Economics (e.g., Jacob Hacker)",
  summary: "Predistribution economics is an approach that aims to create a more equitable distribution of income and wealth by reforming market institutions *before* income is earned, rather than relying solely on taxes and welfare programs to redistribute wealth afterward. Pioneered by thinkers like Jacob Hacker, it focuses on policies that empower workers, strengthen collective bargaining, and ensure fair competition within the market itself. In AI policy, predistribution principles suggest interventions like investing in universal AI literacy and training, promoting worker ownership in AI-driven companies, or designing intellectual property rules that ensure broader access to AI\'s benefits, thereby shaping the market to prevent extreme wealth concentration from the outset.",
  example: "A node tagged with this attribute might propose policies for mandatory worker retraining programs funded by AI companies or advocating for employee stock ownership plans in AI startups.",
  frequency: "Appears in economic and labor policy nodes discussing equitable AI development and wealth distribution.",
  links: [
    { label: "Predistribution", url: "https://en.wikipedia.org/wiki/Predistribution" },
    { label: "Jacob Hacker", url: "https://en.wikipedia.org/wiki/Jacob_Hacker" }
  ]
},
"Prigogine\'s dissipative structures": {
  label: "Prigogine\'s Dissipative Structures",
  summary: "Ilya Prigogine\'s theory of dissipative structures describes open systems that exist far from thermodynamic equilibrium, meaning they constantly exchange energy and matter with their environment. These systems can spontaneously organize into complex, ordered structures by dissipating energy, and they are inherently dynamic and adaptive. In AI policy, this concept helps us understand AI systems and AI-driven societies as complex adaptive systems that are always evolving and interacting with their surroundings. It suggests that policy must account for emergent behaviors, non-linear changes, and the potential for these systems to self-organize or, conversely, to become unstable in unpredictable ways.",
  example: "A node tagged with this attribute might analyze how the global AI ecosystem, with its interconnected research, development, and deployment, exhibits emergent properties that cannot be predicted from individual components.",
  frequency: "Appears in complex systems theory and futurist nodes discussing the long-term evolution and governance of AI.",
  links: [
    { label: "Dissipative structure", url: "https://en.wikipedia.org/wiki/Dissipative_structure" },
    { label: "Ilya Prigogine", url: "https://en.wikipedia.org/wiki/Ilya_Prigogine" }
  ]
},
"principal-agent problem": {
  label: "Principal-Agent Problem",
  summary: "The principal-agent problem describes a conflict of interest that occurs when one party, the \'agent,\' is tasked with making decisions on behalf of another party, the \'principal,\' but the agent\'s own incentives do not perfectly align with the principal\'s goals. This can lead to the agent acting in their own self-interest rather than the principal\'s. In AI policy, this problem is crucial for understanding how to ensure AI systems, acting as agents, reliably serve the interests of their human operators or society, the principals. It highlights challenges in aligning AI\'s objectives with human values, especially when developers\' profit motives might conflict with broader public good or safety.",
  example: "A node tagged with this attribute might discuss how to design regulatory mechanisms to ensure AI developers (agents) prioritize user safety and privacy (principals\' interests) over maximizing engagement or data collection.",
  frequency: "Appears in economic, governance, and ethical nodes discussing AI alignment, accountability, and regulation.",
  links: [
    { label: "Principal–agent problem", url: "https://en.wikipedia.org/wiki/Principal%E2%80%93agent_problem" }
  ]
},
